import{_ as l,I as a,o as i,c,j as e,a as n,J as o}from"./chunks/framework.DYZFTu11.js";const b=JSON.parse('{"title":"《α星篇·其六：迈向黑暗》","description":"","frontmatter":{},"headers":[],"relativePath":"zh_cn/novels/shuangxingluji/chapter-08.md","filePath":"zh_cn/novels/shuangxingluji/chapter-08.md","lastUpdated":1773498699000}'),p={name:"zh_cn/novels/shuangxingluji/chapter-08.md"};function d(h,t,u,_,g,m){const s=a("NolebaseGitContributors"),r=a("NolebaseGitChangelog");return i(),c("div",null,[t[0]||(t[0]=e("h1",{id:"《α星篇·其六-迈向黑暗》",tabindex:"-1"},[e("strong",null,"《α星篇·其六：迈向黑暗》"),n(),e("a",{class:"header-anchor",href:"#《α星篇·其六-迈向黑暗》","aria-label":"Permalink to “《α星篇·其六：迈向黑暗》”"},"​")],-1)),t[1]||(t[1]=e("p",null,[e("strong",null,"《α星篇·其六：迈向黑暗》"),n(' 夜幕低垂，荒原笼罩在深蓝色的暗影中，只有稀疏的星光洒落下来，为干燥的野草镀上一层微弱的银边。尼尔德的帐篷前，防风的油灯在风中摇曳，昏黄的光线将帘幕的阴影拉得忽长忽短。叶子掀开厚重的帆布门帘，冷风立刻灌入，吹乱了她额前的碎发。星溯紧随其后，两人一言不发地走向营地边缘那片被黑暗吞噬的空地。 枯黄的野草在夜风中簌簌作响，像是无数细小的生物在窃窃私语。叶子停下脚步，锐利的目光穿透黑暗，扫视着四周的每一个角落。确认无人后，她才低声开口，声音几乎被风声淹没："真是...该说是命运的玩笑吗？"她踢了踢脚下的碎石，碎石滚动的声响在寂静中格外清晰，"兜兜转转又回到了原点。" 星溯双臂交叠在胸前，护具在月光下泛着冷光。她仰头望向夜空，那里有几颗格外明亮的星星："确实讽刺..."她的声音干涩，"本来还以为这次去不了研究所了，或许这就是宿命的安排..."尾音消散在风中，仿佛从未存在过。沉默片刻后，她突然转向叶子："对了...我有个疑问。" "嗯？"叶子蹲下身，手指在干枯的草茎间摸索，最终拔起一根叼在嘴边。草汁的苦涩在舌尖蔓延，让她想起某个同样寒冷的夜晚。 "你曾说灵裔的首要目标就是研究所。"星溯的声音压得很低，几乎像是在自言自语，"你觉得...那里还会剩下什么吗？"她的叹息里带着长途跋涉后的疲惫，眼下的阴影在月光中更加明显。 黑暗中传来叶子吐出草茎的声音："应该会有收获。"她站起身，战术靴碾过干枯的草地，"毕竟那里是守备最森严的区域，灵裔大概还没顾得上搜刮。"她停顿了一下，声音变得更加低沉，"而且...据说里面还有归家者的机器人，八成是抢来的战利品。" "归家者？"星溯的声音突然提高了几分 叶子耸耸肩，这个动作在月光下只是一个模糊的轮廓："关于这个..."她抬头望向星空，"我只能说是个...天外来客。" "外星人么..."星溯喃喃道，这个词汇在夜色中显得格外不真实。长久的沉默后，她看着逐渐西沉的月亮："别想这些了，回去休息吧...明天还有硬仗要打。" 营地里的篝火已经熄灭多时，只有几盏防风的油灯还在坚守。一个年轻的哨兵快步走来，手中的PG-7磁力步枪在升起的太阳光下泛着冷冽的光泽。"两位，"他的声音因为紧张而略显尖锐，"尼尔德队长请你们过去。" 当时钟的指针指向八点三十分，整装待发的两人站在营地中央。尼尔德正在对集结的战士们做最后的战前动员，油灯的光线将他严峻的面容映得忽明忽暗。直到"解散"的口令响起，她们才快步上前。 "准备就绪了？"尼尔德的声音紧绷如弦，眼睛下方的青黑在灯光中更加明显。 叶子调整着戴在头上的夜视仪的松紧带："还以为要出发了，"她敏锐地注意到尼尔德手指无意识的颤抖，"有什么变故？" "最后的战术部署。"尼尔德展开一张泛黄的地图，油灯的光线让上面的墨迹显得模糊不清。他的指尖重重按在研究所的位置："侦察兵报告，灵裔正与第三方交火——东边的天空都被火光照亮了。" "天赐良机。"星溯的眼睛在尚未升起的太阳传来的光中闪烁着捕食者般的光芒。 "正是。"尼尔德的声音里没有喜悦，"我们要让这场混乱持续更久。"他指向地图边缘的一处标记，"会用改装车搭载重机枪，遥控突袭制造更多混乱。" "但拖延不了太久。"叶子的声音传来 "别无选择。"尼尔德卷起地图时，纸张发出脆弱的声响，"等他们反应过来..."他的喉结滚动了一下，"就只能靠子弹说话了。" "赴死的单程票啊。"叶子轻抚枪管，金属的冰凉触感透过手套传来。 尼尔德的目光在油灯的光线下显得格外深邃："没错，战友们。"他的声音突然变得很轻，"但我们已经...退无可退了。"他转身走向指挥车的背影被拉得很长，几乎融入地面之中，"去领取“单程票"吧，三十分钟后出击。"晨风吹过，将最后的话语吹散在无尽的天空中。')],-1)),o(s),o(r)])}const x=l(p,[["render",d]]);export{b as __pageData,x as default};
